vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret = vec3(1,1,1)*GetBlur3(vUv).x;
ret = mix( ret, vec3(0.6,1,1), GetBlur2(vUv).x*2);
ret = mix( ret, vec3(0,1,1), GetBlur1(vUv).x*0.5);
ret = mix( ret, vec3(-0.3,0,0), GetPixel(vUv).x);


vec2 uv2 = vUv-.5;
uv2 = vec2((uv2.x)*q3 - (uv2.y) * q2,(uv2.x)* q2 + (uv2.y) * q3)+.5;

ret = mix(ret,vec3(1,1,1),texture(sampler_main,uv2).y);
ret = mix( ret, vec3(.6,1,1), GetBlur2(uv2).y*2);
ret = mix( ret, vec3(1,0,1), GetBlur1(uv2).y*0.5);
ret = mix( ret, vec3(-.3,0,0), GetPixel(uv2).y);

  fragColor = ret;
}
